import java.io.*; import java.util.*; public class SafeOpener { public static void main(String args[]) throws IOException { BufferedReader keyboard = new BufferedReader(new InputStreamReader(System.in)); Base64.Encoder encoder = Base64.getEncoder(); String encodedkey = &#34;&#34;; String key = &#34;&#34;; int i = 0; boolean isOpen; while (i &lt; 3) { System.out.print(&#34;Enter password for the safe: &#34;); key = keyboard.readLine(); encodedkey = encoder.encodeToString(key.getBytes()); System.out.println(encodedkey); isOpen = openSafe(encodedkey); if (!isOpen) { System.out.println(&#34;You have &#34; + (2 - i) + &#34; attempt(s) left&#34;); i++; continue; } break; } } public static boolean openSafe(String password) { String encodedkey = &#34;cGwzYXMzX2wzdF9tM18xbnQwX3RoM19zYWYz&#34;; if (password.equals(encodedkey)) { System.out.println(&#34;Sesame open&#34;); return true; } else { System.out.println(&#34;Password is incorrect\n&#34;); return false; } } } En el código podemos ver que tenemos un objeto que codifica cadenas en base64 eso nos da una pista de por donde va el programa
Base64.Encoder encoder = Base64.getEncoder();
También podemos ver que nos pide una contraseña y la almacena en key:
System.out.print(&quot;Enter password for the safe: &quot;); key = keyboard.readLine();
Ahora esta key la codifica en base64
encodedkey = encoder.encodeToString(key.getBytes()); System.out.println(encodedkey);
Mas adelante para verificar que la contraseña sea correcta la compara con una cadena:
String encodedkey = &quot;cGwzYXMzX2wzdF9tM18xbnQwX3RoM19zYWYz&quot;;
if (password.equals(encodedkey)) { System.out.println(&#34;Sesame open&#34;); return true; Perfecto ya hemos visto como funciona la verificación, sabemos que compara una cadena codificada en base64 con otra cadena hardcodeada por lo que intuimos que esta cadena también esta en base64 por lo que si la decodificamos encontraremos la contraseña:
echo &#39;cGwzYXMzX2wzdF9tM18xbnQwX3RoM19zYWYz&#39; | base64 -d Vemos que la contraseña es correcta!
